FORBIDDEN=('recursive.com','recursive org','recursive-style','competitor comparison','named competitor')

def fail(m:str): raise RuntimeError(m)
def load(p:Path)->dict[str,Any]: return json.loads(p.read_text(encoding='utf-8'))
def dump(p:Path,v:Any): p.parent.mkdir(parents=True,exist_ok=True); p.write_text(json.dumps(v,indent=2,ensure_ascii=False)+'\n',encoding='utf-8')
def sha(p:Path)->str: return hashlib.sha256(p.read_bytes()).hexdigest()
def esc(v:Any)->str: return html.escape(str(v),quote=True)

def validate(c,m):
    if c.get('missionId')!='GOALOS-PUBLIC-PROOF-MISSION-005' or c.get('sequence')!=5: fail('wrong Mission 005 identity')
    if c.get('status')!='PROTOCOL_PUBLISHED_AWAITING_THREE_INSTITUTION_PROVEN_MEMBERS': fail('unexpected Mission 005 status')
    if len(c.get('proofRoute',[]))!=40: fail('Mission 005 proof route must contain 40 stages')
    if len(c.get('validators',[]))!=6: fail('Mission 005 requires six validators')
    if len(c.get('commonwealthTrial',{}).get('acts',[]))!=5: fail('Mission 005 requires five acts')
    if sum(int(x.get('share',0)) for x in c.get('settlement',[]))!=100: fail('settlement must total 100')
    b=c.get('missionBudget',{})
    if b.get('independentReplayInstitutions')!=3 or b.get('challengeWindowHours')!=504: fail('replay/challenge policy mismatch')
    if c.get('mission6',{}).get('status')!='HORIZON_ONLY_NOT_YET_AUTHORIZED': fail('Mission 006 must remain horizon only')
    if m.get('chainId')!=1 or m.get('canonicalAgialpha','').lower()!=CANONICAL.lower(): fail('Mainnet identity mismatch')
    if m.get('goalosCreatedContractCount')!=48 or m.get('verification',{}).get('verified')!=48 or m.get('verification',{}).get('failed')!=0: fail('Mainnet evidence mismatch')
    if m.get('phaseBGrantCount')!=14 or m.get('postcheck',{}).get('status')!='PASSED': fail('configuration/postcheck mismatch')
    names={x['name'] for x in m.get('contracts',[])}
    missing=[x['contractName'] for x in c['proofRoute'] if x['contractName'] not in names]
    if missing: fail('unknown contracts: '+', '.join(missing))
    blob=json.dumps(c,ensure_ascii=False).lower()
    for x in FORBIDDEN:
        if x in blob: fail('prohibited public reference: '+x)

def accord_svg()->str:
    nodes=[(250,46,'I','INSTITUTION A'),(432,354,'II','INSTITUTION B'),(68,354,'III','INSTITUTION C')]
    links=''.join(f'<path d="M250 244 L{x} {y}"/>' for x,y,_,_ in nodes)
    ns=''.join(f'<g class="ia-member"><circle cx="{x}" cy="{y}" r="52"/><text class="roman" x="{x}" y="{y-4}" text-anchor="middle">{r}</text><text class="label" x="{x}" y="{y+20}" text-anchor="middle">{t}</text></g>' for x,y,r,t in nodes)
    return f'''<svg class="ia-accord" viewBox="0 0 500 500" role="img" aria-label="Three sovereign institutions joined by a proof-bound accord"><defs><radialGradient id="iaCore"><stop offset="0" stop-color="#fff"/><stop offset=".28" stop-color="#f4d98f"/><stop offset=".62" stop-color="#72e5cd"/><stop offset="1" stop-color="#071725"/></radialGradient><linearGradient id="iaLine"><stop stop-color="#f2cb70"/><stop offset=".5" stop-color="#72e5cd"/><stop offset="1" stop-color="#7ddcff"/></linearGradient><filter id="iaGlow"><feGaussianBlur stdDeviation="5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><circle class="ia-orbit o1" cx="250" cy="250" r="215"/><circle class="ia-orbit o2" cx="250" cy="250" r="158"/><g class="ia-links">{links}<path d="M250 46 432 354 68 354Z"/></g>{ns}<g class="ia-core" filter="url(#iaGlow)"><path d="M250 171 316 210 316 286 250 325 184 286 184 210Z" fill="url(#iaCore)"/><text x="250" y="224" text-anchor="middle">THE</text><text x="250" y="249" text-anchor="middle">ACCORD</text><text class="m5" x="250" y="285" text-anchor="middle">M5</text></g><text class="top" x="250" y="485" text-anchor="middle">PROOF · RECIPROCITY · EXIT · APPEAL</text></svg>'''

