def route_html(c,m):
 by={x['name']:x for x in m['contracts']}; out=[]
 for x in c['proofRoute']:
  d=by[x['contractName']]; search=' '.join([x['stage'],x['contractName'],x['purpose'],d['address']]).lower()
  out.append(f'''<article class="ia-route-item" data-search="{esc(search)}"><b>{x['sequence']:02d}</b><div><small>{esc(x['stage'])}</small><h3>{esc(x['contractName'])}</h3><p>{esc(x['purpose'])}</p><a class="ia-address" href="{esc(d['etherscanUrl'])}" target="_blank" rel="noreferrer">{esc(d['address'])} ↗</a></div></article>''')
 return ''.join(out)

def page(c,m):
 laws=''.join(f'<article class="ia-law">{esc(x)}</article>' for x in c['constitution'])
 arch=''.join(f'''<article class="ia-card {'treatment' if x['id'].startswith('TREATMENT') else ''}"><small>{esc(x['id'])}</small><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in c['controlArchitectures'])
 acts=''.join(f'''<article class="ia-act"><b>{esc(x['id'])}</b><div><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></div></article>''' for x in c['commonwealthTrial']['acts'])
 stack=''.join(f'''<article><strong>{i:02d}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for i,x in enumerate(c['commonwealthStack'],1))
 chain=''.join(f'''<article class="ia-step"><b>{i:02d}</b><div><small>{esc(x['stage'])}</small><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></div></article>''' for i,x in enumerate(c['proofChain'],1))
 gaunt=''.join(f'''<article class="ia-failure"><code>{esc(x['code'])}</code><p>{esc(x['copy'])}</p></article>''' for x in c['commonwealthGauntlet'])
 fails=''.join(f'''<article class="ia-failure"><code>{esc(x['code'])}</code><p>{esc(x['copy'])}</p></article>''' for x in c['failureAtlas'])
 accept=''.join(f'''<article class="ia-criterion"><b>{i}</b><p>{esc(x)}</p></article>''' for i,x in enumerate(c['acceptance'],1))
 vals=''.join(f'''<article class="ia-validator"><strong>{esc(x['id'])}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in c['validators'])
 shares=''.join(f'''<div class="ia-share"><strong>{x['share']}%</strong><div class="ia-bar" style="--w:{max(16,int(x['share'])*3.2)}%">{esc(x['label'])}</div></div>''' for x in c['settlement'])
 ladder=''.join(f'''<article class="ia-level"><strong>{esc(x['level'])}</strong><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>''' for x in c['maturityLadder'])
 claims=''.join(f'<li>{esc(x)}</li>' for x in c['claimBoundary'])
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Public Proof Mission 005 — The Interinstitutional Accord | GoalOS</title><meta name="description" content="Can Institution-Proven systems cooperate through reciprocal proof without surrendering local sovereignty, exit, appeal, or human authority?"><meta property="og:title" content="The Interinstitutional Accord — GoalOS Public Proof Mission 005"><meta property="og:description" content="Where sovereign institutions learn to cooperate without surrendering sovereignty."><meta property="og:type" content="website"><meta name="theme-color" content="#061522"><link rel="stylesheet" href="assets/goalos-v86-preserve.css">{css()}</head><body class="ia-body"><a class="ia-skip" href="#mission">Skip to mission</a><header class="ia-nav"><div class="ia-shell ia-navin"><a class="ia-brand" href="index.html">GoalOS <span>AGIALPHA</span></a><nav class="ia-navlinks"><a href="proof-missions.html">Proof Missions</a><a href="proof-gradient-challenge.html">001</a><a href="proof-mission-002.html">002</a><a href="proof-mission-003.html">003</a><a href="proof-mission-004.html">004</a><a href="#mainnet">Mainnet route</a><a href="{esc(c['releaseUrl'])}" target="_blank" rel="noreferrer">Release ↗</a></nav></div></header><main id="mission"><section class="ia-hero"><div class="ia-shell ia-grid"><div><div class="ia-kicker">{esc(c['kicker'])}</div><h1>THE INTERINSTITUTIONAL <span>ACCORD</span></h1><p class="ia-tag">{esc(c['subtitle'])}</p><p class="ia-question">{esc(c['heroQuestion'])}</p><div class="ia-manifesto">{esc(c['manifesto'])}</div><span class="ia-status">Protocol published · awaiting three Institution-Proven members</span><div class="ia-actions"><a class="ia-btn primary" href="#trial">Enter the commonwealth trial</a><a class="ia-btn" href="proof-missions.html">Open all Proof Missions</a><a class="ia-btn" href="#mainnet">Inspect the Mainnet route</a></div></div><div class="ia-visual">{accord_svg()}</div></div></section>
<section class="ia-section deep"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The constitution</div><h2>Cooperation without domination. Shared action without surrendered sovereignty.</h2><p>{esc(c['publicThesis'])}</p></div><div class="ia-laws">{laws}</div></div></section>
<section class="ia-section light" id="trial"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The interinstitutional experiment</div><h2>Three architectures. One shared objective. Only one preserves proof and exit.</h2><p>{esc(c['objective'])}</p></div><div class="ia-architectures">{arch}</div><div class="ia-metrics"><article class="ia-metric"><strong>3–7</strong><span>Institution-Proven members</span></article><article class="ia-metric"><strong>480h</strong><span>maximum compute envelope</span></article><article class="ia-metric"><strong>6</strong><span>independent validators</span></article><article class="ia-metric"><strong>21 days</strong><span>public challenge window</span></article></div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The Five-Act Commonwealth Trial</div><h2>Ratify. Exchange. Execute. Contest. Renew—or dissolve.</h2><p>{esc(c['commonwealthTrial']['brief'])}</p></div><div class="ia-acts">{acts}</div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The commonwealth stack</div><h2>A federation is not a bigger institution. It is the governed space between institutions.</h2></div><div class="ia-stack">{stack}</div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The proof chain</div><h2>Every treaty action must remain reconstructible from ratification to exit.</h2></div><div class="ia-chain">{chain}</div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The commonwealth gauntlet</div><h2>Mission 005 attacks the boundaries between institutions.</h2><p>Success requires reciprocal accountability, contained failure, credible appeal, and portable exit.</p></div><div class="ia-gauntlet">{gaunt}</div><div style="height:3rem"></div><div class="ia-heading"><div class="ia-eyebrow">The failure atlas</div><h2>Federation failure must become visible before cooperation becomes domination.</h2></div><div class="ia-failures">{fails}</div></div></section>
<section class="ia-section deep"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">Acceptance standard</div><h2>M5 is earned only by reciprocal proof across sovereign institutions.</h2><p>No deployment, website, signature, vote, or consensus label can satisfy this mission alone.</p></div><div class="ia-acceptance">{accept}</div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">Six-validator council</div><h2>No institution may judge its own decisive claim.</h2></div><div class="ia-validators">{vals}</div></div></section>
<section class="ia-section light"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">Reciprocal settlement</div><h2>Shared value follows accepted contribution—and every externality remains an obligation.</h2><p>Settlement remains conditional on accepted mission proof, exact reconciliation, challenge closure, portable exit, and valid human ratification.</p></div><div class="ia-settlement"><div class="ia-seal"><div>PROOF<br>COMMONWEALTH<br>THERMOSTAT</div></div><div>{shares}</div></div></div></section>
<section class="ia-section deep"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">The maturity ladder</div><h2>Trust becomes federation only through narrower, cumulative proof.</h2></div><div class="ia-ladder">{ladder}</div></div></section>
<section class="ia-section light" id="mainnet"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">Ethereum Mainnet proof route</div><h2>Forty interinstitutional stages mapped to deployed GoalOS infrastructure.</h2><p>The recorded deployment contains 48 GoalOS-created contracts, 48/48 source verification, 14 configured grants, and a passing 48-contract postcheck. Infrastructure existence is public. Mission 005 outcomes remain evidence-gated.</p></div><div class="ia-route-tools"><input id="ia-route-search" type="search" placeholder="Search stage, contract, purpose, or address"><span class="ia-route-count"><span id="ia-route-visible">40</span> / 40 stages</span></div><div class="ia-route">{route_html(c,m)}</div></div></section>
<section class="ia-section gold"><div class="ia-shell"><div class="ia-heading"><div class="ia-eyebrow">Claim boundary</div><h2>Grand cooperation. Exact language. No result predeclared.</h2></div><article class="ia-claim"><ul>{claims}</ul><div class="ia-downloads"><a href="downloads/proof-missions/public-proof-mission-005.json">Mission 005 JSON</a><a href="downloads/proof-missions/mission-005-commonwealth-treaty-template.json">Treaty template</a><a href="downloads/proof-missions/mission-005-reciprocal-obligation-ledger-template.json">Obligation ledger</a><a href="downloads/proof-missions/mission-005-dispute-appeal-template.json">Dispute & appeal template</a><a href="downloads/proof-missions/mission-005-member-exit-template.json">Member exit template</a><a href="downloads/proof-missions/mission-005-proof-route.csv">Mainnet route CSV</a></div></article><article class="ia-horizon"><strong>MISSION 006 HORIZON</strong><h2>{esc(c['mission6']['title'])}</h2><p>{esc(c['mission6']['copy'])}</p><span class="ia-status" style="color:#071521;border-color:rgba(7,21,33,.25);background:rgba(255,255,255,.28)">Horizon only · not authorized</span></article></div></section></main><footer class="ia-footer"><div class="ia-shell">GoalOS AGIALPHA Ascension · Public Proof Mission 005 · Not externally audited · No federation result predeclared</div></footer><script src="assets/goalos-v86-dynamic-ai.js" defer></script><script>const q=document.getElementById('ia-route-search'),items=[...document.querySelectorAll('.ia-route-item')],n=document.getElementById('ia-route-visible');if(q)q.addEventListener('input',()=>{{const s=q.value.trim().toLowerCase();let c=0;items.forEach(x=>{{const y=!s||x.dataset.search.includes(s);x.classList.toggle('hidden',!y);if(y)c++}});n.textContent=c}});</script></body></html>'''

def hub_page(c):
 cards=[('001','The Proof Gradient','Turn autonomous output into accepted capability through falsification, replay, validator decision, settlement, and Chronicle memory.','proof-gradient-challenge.html','M1 · Accepted'),('002','The Ascension Protocol','Test whether accepted capability survives a harder domain, a lower budget, abstention, independent replay, and rollback.','proof-mission-002.html','M2 · Transfer-Proven'),('003','The Capability Constellation','Test whether multiple Transfer-Proven capabilities compose safely through interfaces, fault domains, attribution, collective replay, and rollback.','proof-mission-003.html','M3 · Composition-Proven'),('004','The Sovereign Institution','Test whether one Composition-Proven constellation can operate through repeated mandates, proof-budgeted capital, shocks, succession, and human renewal.','proof-mission-004.html','M4 · Institution-Proven'),('005','The Interinstitutional Accord','Test whether independent institutions can cooperate through reciprocal proof while preserving local sovereignty, appeal, exit, and human ratification.',PAGE,'M5 · Federation-Proven')]
 cards_html=''.join(f'''<article class="pm-card m{n[-1]}"><div class="pm-num">PUBLIC PROOF MISSION {n}</div><h3>{esc(t)}</h3><p>{esc(x)}</p><span class="pm-status">{esc(l)}</span><a class="pm-button" href="{u}">Enter Mission {n[-1]}</a></article>''' for n,t,x,u,l in cards)
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>The Proof Missions | GoalOS AGIALPHA Ascension</title><meta name="description" content="The GoalOS Public Proof Missions: acceptance, transfer, composition, institution, and proof-governed federation."><meta name="theme-color" content="#061522"><link rel="stylesheet" href="assets/goalos-v86-preserve.css"><style id="goalos-v86-critical">:root{{--pm-bg:#030711;--pm-gold:#f2cb70;--pm-mint:#72e5cd;--pm-cyan:#7ddcff;--pm-violet:#a99cff}}*{{box-sizing:border-box}}body{{margin:0;background:var(--pm-bg);color:#eef7fb;font-family:Inter,system-ui,sans-serif}}a{{color:inherit}}.pm-shell{{width:min(1180px,calc(100% - 2rem));margin:auto}}.pm-nav{{position:sticky;top:0;z-index:10;background:rgba(3,7,17,.9);backdrop-filter:blur(18px);border-bottom:1px solid rgba(255,255,255,.13)}}.pm-navin{{min-height:70px;display:flex;align-items:center;justify-content:space-between;gap:1rem}}.pm-brand{{font-weight:1000;text-decoration:none}}.pm-brand span{{color:var(--pm-gold)}}.pm-links{{display:flex;gap:.35rem;flex-wrap:wrap}}.pm-links a{{font-size:.78rem;text-decoration:none;color:#c6d7df;padding:.52rem .6rem;border-radius:999px}}.pm-links a:hover{{background:rgba(255,255,255,.08);color:#fff}}.pm-hero{{padding:8rem 0 6rem;position:relative;overflow:hidden;background:radial-gradient(circle at 76% 25%,rgba(114,229,205,.17),transparent 25%),radial-gradient(circle at 20% 70%,rgba(169,156,255,.14),transparent 29%),linear-gradient(160deg,#02050d,#0a2030)}}.pm-hero:before{{content:"";position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,.45) 0 1px,transparent 1.5px);background-size:74px 74px;opacity:.15}}.pm-hero-in{{position:relative}}.pm-kicker{{color:var(--pm-gold);font-size:.71rem;text-transform:uppercase;letter-spacing:.15em;font-weight:1000}}.pm-hero h1{{font-size:clamp(4rem,10vw,8.5rem);line-height:.82;letter-spacing:-.075em;margin:1rem 0}}.pm-hero h1 span{{display:block;color:transparent;background:linear-gradient(90deg,var(--pm-gold),#fff 38%,var(--pm-mint),var(--pm-cyan));background-clip:text}}.pm-lead{{max-width:930px;font-size:clamp(1.18rem,2.2vw,1.63rem);line-height:1.55;color:#d6e4ea}}.pm-law{{margin-top:2rem;max-width:980px;padding:1.1rem 1.25rem;border-left:3px solid var(--pm-mint);background:linear-gradient(90deg,rgba(114,229,205,.12),transparent);font-weight:900;line-height:1.55}}.pm-section{{padding:6.5rem 0}}.pm-section.light{{background:#faf6ec;color:#071521}}.pm-heading{{max-width:930px;margin-bottom:2.5rem}}.pm-heading h2{{font-size:clamp(2.5rem,5vw,4.8rem);line-height:.98;letter-spacing:-.055em;margin:.75rem 0}}.pm-heading p{{font-size:1.1rem;line-height:1.7;color:#aebfcc}}.light .pm-heading p{{color:#526776}}.pm-grid{{display:grid;grid-template-columns:repeat(2,1fr);gap:1rem}}.pm-card{{min-height:390px;padding:2rem;border:1px solid rgba(255,255,255,.14);border-radius:28px;background:rgba(255,255,255,.045);display:flex;flex-direction:column;position:relative;overflow:hidden}}.pm-card:after{{content:"";position:absolute;width:210px;height:210px;border-radius:50%;right:-70px;top:-70px;background:radial-gradient(circle,rgba(242,203,112,.2),transparent 70%)}}.pm-card.m2:after{{background:radial-gradient(circle,rgba(114,229,205,.2),transparent 70%)}}.pm-card.m3:after{{background:radial-gradient(circle,rgba(169,156,255,.2),transparent 70%)}}.pm-card.m4:after{{background:radial-gradient(circle,rgba(125,220,255,.21),transparent 70%)}}.pm-card.m5{{grid-column:1/-1;min-height:350px;background:linear-gradient(145deg,rgba(242,203,112,.08),rgba(114,229,205,.08),rgba(255,255,255,.045));border-color:rgba(242,203,112,.34)}}.pm-num{{font-size:.71rem;font-weight:1000;letter-spacing:.14em;color:var(--pm-gold);position:relative;z-index:1}}.pm-card h3{{font-size:clamp(2rem,4vw,3.2rem);line-height:.94;letter-spacing:-.05em;margin:.8rem 0;position:relative;z-index:1}}.pm-card p{{color:#c3d4dc;line-height:1.67;font-size:1.02rem;position:relative;z-index:1}}.pm-status{{display:inline-flex;align-self:flex-start;margin-top:auto;padding:.55rem .7rem;border:1px solid rgba(255,255,255,.16);border-radius:999px;color:#c9dbe3;font-size:.72rem;font-weight:900;position:relative;z-index:1}}.pm-button{{display:inline-flex;align-self:flex-start;margin-top:1rem;padding:.72rem .9rem;border-radius:999px;text-decoration:none;background:#fff;color:#071521;font-weight:950;position:relative;z-index:1}}.pm-ladder{{display:grid;grid-template-columns:repeat(5,1fr);gap:.8rem}}.pm-step{{padding:1.35rem;border-radius:22px;background:#fff;border:1px solid rgba(5,16,24,.1)}}.pm-step strong{{font-size:2.1rem;color:#0d8d78}}.pm-step h3{{font-size:1.2rem;margin:.5rem 0}}.pm-step p{{color:#526776;line-height:1.58}}.pm-stats{{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem}}.pm-stat{{padding:1.4rem;border:1px solid rgba(255,255,255,.14);border-radius:20px;background:rgba(255,255,255,.045)}}.pm-stat strong{{display:block;font-size:2.8rem}}.pm-stat span{{color:#b9cdd7;font-size:.82rem;font-weight:800}}.pm-horizon{{padding:2.2rem;border:1px solid rgba(255,255,255,.16);border-radius:28px;background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(255,255,255,.025))}}.pm-horizon h3{{font-size:clamp(2.5rem,5vw,4.8rem);letter-spacing:-.05em;margin:.7rem 0}}.pm-horizon p{{max-width:900px;color:#c4d6df;line-height:1.7}}.pm-footer{{padding:2rem 0;border-top:1px solid rgba(255,255,255,.12);color:#91a7b3}}@media(max-width:900px){{.pm-ladder{{grid-template-columns:1fr 1fr}}}}@media(max-width:650px){{.pm-links{{display:none}}.pm-grid,.pm-ladder,.pm-stats{{grid-template-columns:1fr}}.pm-card.m5{{grid-column:auto}}.pm-hero{{padding:5.5rem 0 4rem}}}}</style></head><body><header class="pm-nav"><div class="pm-shell pm-navin"><a class="pm-brand" href="index.html">GoalOS <span>AGIALPHA</span></a><nav class="pm-links"><a href="proof-gradient-challenge.html">001</a><a href="proof-mission-002.html">002</a><a href="proof-mission-003.html">003</a><a href="proof-mission-004.html">004</a><a href="proof-mission-005.html">005</a><a href="{esc(c['repositoryUrl'])}" target="_blank" rel="noreferrer">GitHub ↗</a></nav></div></header><main><section class="pm-hero"><div class="pm-shell pm-hero-in"><div class="pm-kicker">GoalOS Public Program · Ethereum Mainnet</div><h1>THE PROOF <span>MISSIONS</span></h1><p class="pm-lead">A public program for turning autonomous work into accepted capability, transfer evidence, safe composition, accountable institutions, and proof-governed cooperation across sovereign institutions.</p><div class="pm-law">A model can answer. An agent can act. An institution must prove. A commonwealth must prove that cooperation remains reciprocal, contestable, reversible, and subordinate to human authority.</div></div></section><section class="pm-section"><div class="pm-shell"><div class="pm-heading"><div class="pm-kicker">The mission sequence</div><h2>Trust. Transfer. Composition. Institution. Accord. No maturity without proof.</h2><p>Each mission earns one narrower propagation right. None inherits credibility from ambition.</p></div><div class="pm-grid">{cards_html}</div></div></section><section class="pm-section light"><div class="pm-shell"><div class="pm-heading"><div class="pm-kicker">The maturity ladder</div><h2>Proof earns propagation rights in stages.</h2></div><div class="pm-ladder"><article class="pm-step"><strong>01</strong><h3>Earn trust</h3><p>Accept work only after falsification, hidden evaluation, replay, and validator quorum.</p></article><article class="pm-step"><strong>02</strong><h3>Survive transfer</h3><p>Test whether accepted capability accelerates harder work and abstains outside evidence.</p></article><article class="pm-step"><strong>03</strong><h3>Compose safely</h3><p>Prove interfaces, fault domains, attribution, shared memory, full replay, and rollback.</p></article><article class="pm-step"><strong>04</strong><h3>Operate institutionally</h3><p>Prove repeated mandates, bounded capital, shocks, succession, renewal, and termination.</p></article><article class="pm-step"><strong>05</strong><h3>Cooperate reciprocally</h3><p>Prove treaty, local sovereignty, shared obligations, dispute, appeal, exit, and dissolution.</p></article></div></div></section><section class="pm-section"><div class="pm-shell"><div class="pm-heading"><div class="pm-kicker">The deployed substrate</div><h2>The proof routes are anchored in real Mainnet infrastructure.</h2><p>Infrastructure existence is public. Mission outcomes remain evidence-gated.</p></div><div class="pm-stats"><div class="pm-stat"><strong>48</strong><span>GoalOS-created Mainnet contracts</span></div><div class="pm-stat"><strong>48/48</strong><span>recorded source verification</span></div><div class="pm-stat"><strong>14/14</strong><span>configuration grants active</span></div><div class="pm-stat"><strong>0</strong><span>recorded verification failures</span></div></div></div></section><section class="pm-section"><div class="pm-shell"><div class="pm-horizon"><div class="pm-kicker">Mission 006 horizon</div><h3>{esc(c['mission6']['title'])}</h3><p>{esc(c['mission6']['copy'])}</p><p><strong>Status:</strong> horizon only; not yet authorized.</p></div></div></section></main><footer class="pm-footer"><div class="pm-shell">GoalOS AGIALPHA Ascension · The Proof Missions · Not externally audited · No mission result predeclared</div></footer><script src="assets/goalos-v86-dynamic-ai.js" defer></script></body></html>'''

def home_style():
 return f'''{STYLE_START}<style>.ia-home{{position:relative;overflow:hidden;padding:7.2rem 0;background:radial-gradient(circle at 79% 24%,rgba(114,229,205,.18),transparent 25%),radial-gradient(circle at 18% 70%,rgba(169,156,255,.11),transparent 29%),radial-gradient(circle at 52% 92%,rgba(242,203,112,.12),transparent 25%),linear-gradient(145deg,#02060e,#0a2232);color:#eef7fb;border-top:1px solid rgba(255,255,255,.12);border-bottom:1px solid rgba(255,255,255,.12)}}.ia-home:before{{content:"";position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,.42) 0 1px,transparent 1.5px);background-size:63px 63px;opacity:.15}}.ia-home-in{{position:relative;z-index:1;width:min(1180px,calc(100% - 2rem));margin:auto;display:grid;grid-template-columns:1.05fr .95fr;gap:3rem;align-items:center}}.ia-home-kicker{{text-transform:uppercase;letter-spacing:.16em;color:#f2cb70;font-size:.72rem;font-weight:1000}}.ia-home h2{{font-size:clamp(3rem,7vw,6.1rem);line-height:.87;letter-spacing:-.068em;margin:.8rem 0 1.2rem}}.ia-home h2 span{{display:block;font-size:.62em;white-space:nowrap;color:transparent;background:linear-gradient(90deg,#f2cb70,#fff 42%,#72e5cd,#7ddcff);background-clip:text}}.ia-home p{{font-size:1.15rem;line-height:1.65;color:#cddde5;max-width:720px}}.ia-home-law{{font-family:Georgia,serif;font-size:1.18rem;font-style:italic;color:#f4dc9c;margin:1rem 0}}.ia-home-actions{{display:flex;gap:.7rem;flex-wrap:wrap;margin-top:1.5rem}}.ia-home-actions a{{padding:.78rem 1rem;border:1px solid rgba(255,255,255,.22);border-radius:999px;text-decoration:none;font-weight:950}}.ia-home-actions a:first-child{{background:#f2cb70;color:#061018;border-color:transparent}}.ia-home-stats{{display:grid;grid-template-columns:repeat(2,1fr);gap:.65rem;margin-top:1.3rem}}.ia-home-stat{{padding:.9rem;border:1px solid rgba(255,255,255,.14);border-radius:16px;background:rgba(255,255,255,.045)}}.ia-home-stat strong{{display:block;font-size:1.5rem}}.ia-home-stat span{{font-size:.78rem;color:#abc0cc}}.ia-home-visual{{position:relative;aspect-ratio:1;display:grid;place-items:center}}.ia-home-ring{{position:absolute;border:1px dashed rgba(255,255,255,.22);border-radius:50%;inset:8%}}.ia-home-ring.r2{{inset:23%;border-color:rgba(242,203,112,.25)}}.ia-home-core{{width:34%;aspect-ratio:1;border-radius:50%;display:grid;place-items:center;text-align:center;background:radial-gradient(circle at 35% 30%,#fff,#f2cb70 38%,#72e5cd 74%,#071426);color:#07121d;font-weight:1000;z-index:2;box-shadow:0 0 62px rgba(114,229,205,.3)}}.ia-home-node{{position:absolute;width:82px;aspect-ratio:1;border-radius:50%;display:grid;place-items:center;text-align:center;background:#071426;border:1px solid rgba(255,255,255,.22);font-size:.64rem;font-weight:950}}.ia-home-node.n1{{top:2%;left:39%}}.ia-home-node.n2{{right:6%;bottom:17%}}.ia-home-node.n3{{left:6%;bottom:17%}}@media(max-width:820px){{.ia-home-in{{grid-template-columns:1fr}}.ia-home-visual{{max-width:460px;margin:auto;width:100%}}}}@media(max-width:520px){{.ia-home{{padding:4.7rem 0}}.ia-home h2{{font-size:3.15rem}}.ia-home h2 span{{white-space:normal}}.ia-home-actions a{{width:100%;text-align:center}}}}</style>{STYLE_END}'''

def home_section():
 return f'''{START}<section class="ia-home"><div class="ia-home-in"><div><div class="ia-home-kicker">Public Proof Mission 005 · Proof Commonwealth</div><h2>THE INTERINSTITUTIONAL <span>ACCORD</span></h2><p><strong>Where sovereign institutions learn to cooperate without surrendering sovereignty.</strong> Mission 005 tests whether Institution-Proven systems can share capability and capital, resolve disputes, survive defection, preserve local authority, and dissolve cleanly under reciprocal proof.</p><div class="ia-home-law">No treaty without proof. No shared resource without reciprocal accountability. No federation without exit, appeal, and human sovereignty.</div><div class="ia-home-stats"><div class="ia-home-stat"><strong>3–7 members</strong><span>independent Institution-Proven systems</span></div><div class="ia-home-stat"><strong>480h</strong><span>maximum compute envelope</span></div><div class="ia-home-stat"><strong>6 validators</strong><span>independent commonwealth quorum</span></div><div class="ia-home-stat"><strong>40 stages</strong><span>Ethereum Mainnet proof route</span></div></div><div class="ia-home-actions"><a href="{PAGE}">Enter Mission 005</a><a href="{HUB}">Open the Proof Missions</a><a href="{PAGE}#mainnet">Inspect the Mainnet route</a></div></div><div class="ia-home-visual"><div class="ia-home-ring"></div><div class="ia-home-ring r2"></div><div class="ia-home-core">M5<br>ACCORD</div><div class="ia-home-node n1">INSTITUTION<br>A</div><div class="ia-home-node n2">INSTITUTION<br>B</div><div class="ia-home-node n3">INSTITUTION<br>C</div></div></div></section>{END}'''

def replace_marked(t,s,e,r): return re.sub(re.escape(s)+r'.*?'+re.escape(e),r,t,flags=re.S)
def inject_home(p:Path):
 raw=p.read_text(); st=home_style(); sec=home_section()
 raw=replace_marked(raw,STYLE_START,STYLE_END,st) if STYLE_START in raw else raw.replace('</head>',st+'\n</head>',1)
 if START in raw: raw=replace_marked(raw,START,END,sec)
 elif M4_END in raw: raw=raw.replace(M4_END,M4_END+'\n'+sec,1)
 else: fail('Mission 004 homepage marker not found')
 p.write_text(raw)

def promote_m4(p:Path):
 raw=p.read_text(); active=f'''{PROMO_START}<article class="si-horizon"><strong>PUBLIC PROOF MISSION 005 · NOW PUBLISHED</strong><h2 style="font-size:clamp(2rem,4vw,3.6rem);margin:.7rem 0">The Interinstitutional Accord</h2><p style="font-size:1.12rem;line-height:1.7;color:#19303c">Mission 005 now publishes the protocol for proof-bound treaties, reciprocal resources, cross-institution challenge, formal appeal, portable exit, independent replay, and human-ratified renewal or dissolution.</p><p><a class="si-btn primary" href="proof-mission-005.html">Enter Mission 005</a></p></article>{PROMO_END}'''
 if PROMO_START in raw: raw=replace_marked(raw,PROMO_START,PROMO_END,active)
 else:
  pat=r'<article class="si-horizon"><strong>MISSION 005 HORIZON</strong>.*?</article>'
  raw,n=re.subn(pat,active,raw,count=1,flags=re.S)
  if n!=1: fail('Mission 004 horizon not found')
 p.write_text(raw)

